const headers = $input.first().json.headers || [];
const rows = $input.first().json.data || [];

const mapping = {
  'RFC': 'rfc',
  'rfc': 'rfc',
  'Nombre': 'nombre',
  'nombre': 'nombre',
  'Cliente': 'nombre',
  'Monto': 'monto',
  'monto': 'monto',
  'Importe': 'monto',
  'Cantidad': 'monto',
  'Concepto': 'concepto',
  'concepto': 'concepto',
  'Tipo': 'concepto',
  'Servicio': 'concepto',
  'Fecha': 'fechaVence',
  'fecha': 'fechaVence',
  'Vencimiento': 'fechaVence',
  'Telefono': 'telefono',
  'telefono': 'telefono',
  'Telefono': 'telefono',
  'Email': 'email',
  'email': 'email',
  'Correo': 'email'
};

const mappedRows = rows.map(row => {
  const obj = {};
  row.forEach((value, index) => {
    const header = headers[index];
    const mappedField = mapping[header];
    if (mappedField && value !== undefined && value !== null && value !== '') {
      obj[mappedField] = value;
    }
  });
  if (obj.monto) {
    obj.monto = typeof obj.monto === 'number' ? obj.monto : parseFloat(String(obj.monto).replace(/[$,]/g, '')) || 0;
  }
  return obj;
}).filter(r => r.rfc);

return [{ json: { headers, rows: mappedRows } }];

const client = $('Get Cliente por RFC').first().json;
const operations = $('Get Historial 3 meses').first().json || [];

const pendientes = operations.filter(o => !o.fechaPago);
const pagados = operations.filter(o => o.fechaPago);
const totalPendiente = pendientes.reduce((sum, p) => sum + p.monto, 0);
const totalPagado = pagados.reduce((sum, p) => sum + p.monto, 0);

const conceptosList = pendientes.map((p, i) => `${i + 1}. ${p.descripcion || p.tipo}: $${Number(p.monto).toLocaleString('es-MX')}`).join('
');

const mensaje = `*Collecta* - Recordatorio de Pago

Estimado *${client.nombre}*, le informamos que tiene los siguiente conceptos pendientes:

${conceptosList}

*TOTAL PENDIENTE: $${totalPendiente.toLocaleString('es-MX', {style: 'currency', currency: 'MXN'})}*

Para realizar su pago:
- Beneficiario: BajaTax Services
- Banco: BBVA
- CLABE: 012345678901234567

Historial de pagos (3 meses): $${totalPagado.toLocaleString('es-MX')}

Cobranzas | 6641234567`;

const telefono = client.telefono?.replace(/\D/g, '') || '';
const waUrl = telefono ? `https://wa.me/52${telefono}?text=${encodeURIComponent(mensaje)}` : null;

return [{ json: { mensaje, waUrl, telefono, cliente: client.nombre, rfc: client.rfc, totalPendiente, pendientesCount: pendientes.length } }];
